package com.hogaria.service;
import com.hogaria.dto.CategoryDtos.*;import com.hogaria.entity.Category;import com.hogaria.exception.ForbiddenException;import com.hogaria.repository.*;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.*;import org.mockito.junit.jupiter.MockitoExtension;import java.util.*;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.Mockito.*;
@ExtendWith(MockitoExtension.class)
class CategoryServiceTest { @Mock CategoryRepository categoryRepository; @Mock FinancialProfileRepository profileRepository; @InjectMocks CategoryService service;
@Test void createValid(){var u=UUID.randomUUID();var p=UUID.randomUUID();when(profileRepository.findByIdAndUserId(p,u)).thenReturn(Optional.of(new com.hogaria.entity.FinancialProfile()));when(categoryRepository.save(any())).thenAnswer(i->i.getArgument(0)); var r=service.create(u,p,new CategoryCreateRequest(null,"Comida",Category.Type.VARIABLE_EXPENSE,Category.Scope.PERSONAL)); assertEquals("Comida",r.name());}
@Test void includesGlobal(){var u=UUID.randomUUID();var p=UUID.randomUUID();when(profileRepository.findByIdAndUserId(p,u)).thenReturn(Optional.of(new com.hogaria.entity.FinancialProfile()));when(categoryRepository.findByProfileIdAndActiveTrue(p)).thenReturn(List.of());when(categoryRepository.findByProfileIdIsNullAndActiveTrue()).thenReturn(List.of(Category.builder().name("Global").type(Category.Type.FIXED_EXPENSE).scope(Category.Scope.GLOBAL).active(true).build())); assertEquals(1,service.list(u,p,true).size());}
@Test void rejectEditGlobal(){var c=Category.builder().id(UUID.randomUUID()).scope(Category.Scope.GLOBAL).build();when(categoryRepository.findById(c.getId())).thenReturn(Optional.of(c));assertThrows(ForbiddenException.class,()->service.update(UUID.randomUUID(),c.getId(),new CategoryUpdateRequest(null,"a",null,null,null)));}
}
